import LocalizedClientLink from '@/components/molecules/LocalizedLink/LocalizedLink'
import { navLinks, socialLinks } from '@/data/footerLinks'

/** Discord icon — Lucide doesn't ship one, so we use the brand SVG inline. */
function DiscordIcon({ className }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="currentColor"
      className={className}
      aria-hidden="true"
    >
      <path d="M20.317 4.37a19.791 19.791 0 0 0-4.885-1.515.074.074 0 0 0-.079.037c-.21.375-.444.864-.608 1.25a18.27 18.27 0 0 0-5.487 0 12.64 12.64 0 0 0-.617-1.25.077.077 0 0 0-.079-.037A19.736 19.736 0 0 0 3.677 4.37a.07.07 0 0 0-.032.027C.533 9.046-.32 13.58.099 18.057a.082.082 0 0 0 .031.057 19.9 19.9 0 0 0 5.993 3.03.078.078 0 0 0 .084-.028c.462-.63.874-1.295 1.226-1.994a.076.076 0 0 0-.041-.106 13.107 13.107 0 0 1-1.872-.892.077.077 0 0 1-.008-.128 10.2 10.2 0 0 0 .372-.292.074.074 0 0 1 .077-.01c3.928 1.793 8.18 1.793 12.062 0a.074.074 0 0 1 .078.01c.12.098.246.198.373.292a.077.077 0 0 1-.006.127 12.299 12.299 0 0 1-1.873.892.077.077 0 0 0-.041.107c.36.698.772 1.362 1.225 1.993a.076.076 0 0 0 .084.028 19.839 19.839 0 0 0 6.002-3.03.077.077 0 0 0 .032-.054c.5-5.177-.838-9.674-3.549-13.66a.061.061 0 0 0-.031-.03z" />
    </svg>
  )
}

const iconMap = {
  discord: DiscordIcon,
  twitter: Twitter,
  github: Github,
} as const

export function Footer() {
  return (
    <footer
      className="border-t"
      style={{ borderColor: 'var(--surface-border, var(--border-default))' }}
    >
      <div className="mx-auto flex max-w-[1344px] items-center justify-between px-12 py-12">
        {/* Gradient logo text */}
        <span
          className="font-display text-lg font-bold"
          style={{
            background: 'linear-gradient(135deg, var(--brand-primary), #A78BFA)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            backgroundClip: 'text',
          }}
        >
          SideDecked
        </span>

        {/* Nav links */}
        <nav className="flex gap-6" aria-label="Footer navigation">
          {navLinks.map(({ label, path }) => (
            <LocalizedClientLink
              key={label}
              href={path}
              className="text-[13px] transition-colors duration-150"
              style={{
                color: 'var(--text-tertiary)',
              }}
            >
              {label}
            </LocalizedClientLink>
          ))}
        </nav>

        {/* Social icons */}
        <div className="flex gap-3">
          {socialLinks.map(({ label, href, icon }) => {
            const Icon = iconMap[icon]
            return (
              <a
                key={label}
                href={href}
                target="_blank"
                rel="noopener noreferrer"
                aria-label={label}
                className="flex h-8 w-8 items-center justify-center rounded-lg border transition-all duration-150"
                style={{
                  background: 'var(--bg-surface-2)',
                  borderColor: 'var(--border-default)',
                  color: 'var(--text-tertiary)',
                }}
              >
                <Icon className="h-3.5 w-3.5" />
              </a>
            )
          })}
        </div>
      </div>

      {/* Copyright */}
      <p
        className="mx-auto max-w-[1344px] pb-8 text-center text-xs"
        style={{ color: 'var(--text-tertiary)' }}
      >
        © {new Date().getFullYear()} SideDecked. All rights reserved.
      </p>
    </footer>
  )
}

import { render, screen } from '@testing-library/react'
import { describe, it, expect } from 'vitest'
import { PriceTag } from '../PriceTag'

describe('PriceTag', () => {
  describe('inline variant', () => {
    it('shows formatted price and seller count', () => {
      render(<PriceTag variant="inline" price={15.99} sellerCount={3} />)
      expect(screen.getByText(/\$15\.99/)).toBeInTheDocument()
      expect(screen.getByText(/3 sellers/)).toBeInTheDocument()
    })

    it('shows "No sellers" when price is null', () => {
      render(<PriceTag variant="inline" price={null} />)
      expect(screen.getByText('No sellers')).toBeInTheDocument()
    })

    it('shows singular "seller" for count of 1', () => {
      render(<PriceTag variant="inline" price={5.00} sellerCount={1} />)
      expect(screen.getByText(/1 seller\b/)).toBeInTheDocument()
    })
  })

  describe('detailed variant', () => {
    it('shows price, seller count, and market average', () => {
      render(<PriceTag variant="detailed" price={15.99} sellerCount={3} marketAvg={17.50} />)
      expect(screen.getByText(/\$15\.99/)).toBeInTheDocument()
      expect(screen.getByText(/3 sellers/)).toBeInTheDocument()
      expect(screen.getByText(/\$17\.50/)).toBeInTheDocument()
    })

    it('shows downward trend indicator', () => {
      render(<PriceTag variant="detailed" price={15.99} trend="down" />)
      expect(screen.getByLabelText(/trending down/i)).toBeInTheDocument()
    })

    it('shows upward trend indicator', () => {
      render(<PriceTag variant="detailed" price={15.99} trend="up" />)
      expect(screen.getByLabelText(/trending up/i)).toBeInTheDocument()
    })
  })

  describe('compact variant', () => {
    it('shows only price (no seller count)', () => {
      const { container } = render(<PriceTag variant="compact" price={15.99} sellerCount={3} />)
      expect(screen.getByText(/\$15\.99/)).toBeInTheDocument()
      expect(container.textContent).not.toMatch(/sellers/)
    })

    it('shows "No sellers" when price is null in compact', () => {
      render(<PriceTag variant="compact" price={null} />)
      expect(screen.getByText('No sellers')).toBeInTheDocument()
    })
  })

  describe('accessibility', () => {
    it('has descriptive aria-label on wrapper', () => {
      render(<PriceTag variant="inline" price={15.99} sellerCount={3} />)
      // The component should have an aria-label that is readable by screen readers
      const el = screen.getByRole('group')
      expect(el).toHaveAttribute('aria-label')
    })
  })
})

