import { render, screen, within } from '@testing-library/react'
import { describe, it, expect, vi } from 'vitest'
import { Footer } from '../Footer'

// Mock next/navigation (LocalizedClientLink uses useParams)
vi.mock('next/navigation', () => ({
  useParams: () => ({ locale: 'en' }),
}))

describe('Footer', () => {
  it('renders gradient logo text "SideDecked"', () => {
    render(<Footer />)
    expect(screen.getByText('SideDecked')).toBeInTheDocument()
  })

  it('renders all 5 nav links with correct href paths', () => {
    render(<Footer />)
    const nav = screen.getByRole('navigation', { name: /footer/i })
    const links = within(nav).getAllByRole('link')

    expect(links).toHaveLength(5)

    const expected = [
      { label: 'About', path: '/en/about' },
      { label: 'FAQ', path: '/en/faq' },
      { label: 'Terms', path: '/en/terms' },
      { label: 'Privacy', path: '/en/privacy' },
      { label: 'Contact', path: '/en/contact' },
    ]

    expected.forEach(({ label, path }) => {
      const link = within(nav).getByRole('link', { name: label })
      expect(link).toHaveAttribute('href', path)
    })
  })

  it('renders 3 social links with target="_blank" and rel="noopener noreferrer"', () => {
    render(<Footer />)
    const socialLabels = ['Discord', 'X', 'GitHub']

    socialLabels.forEach((label) => {
      const link = screen.getByRole('link', { name: label })
      expect(link).toHaveAttribute('target', '_blank')
      expect(link).toHaveAttribute('rel', 'noopener noreferrer')
    })
  })

  it('renders copyright text containing current year', () => {
    render(<Footer />)
    const year = new Date().getFullYear().toString()
    expect(screen.getByText(new RegExp(`© ${year}`))).toBeInTheDocument()
  })

  it('does not have bg-primary class anywhere in the rendered output', () => {
    const { container } = render(<Footer />)
    const allElements = container.querySelectorAll('*')
    allElements.forEach((el) => {
      expect(el.className).not.toMatch(/bg-primary/)
    })
  })

  it('has a border-top separator on the footer element', () => {
    const { container } = render(<Footer />)
    const footer = container.querySelector('footer')
    expect(footer).toBeInTheDocument()
    expect(footer!.className).toContain('border-t')
  })
})

